import{_ as e,o as l,c as i,a3 as r}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"多窗口模式","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/advanced/multi-window.md","filePath":"user-guide/advanced/multi-window.md","lastUpdated":1781934556000}'),t={name:"user-guide/advanced/multi-window.md"};function o(h,a,d,n,u,s){return l(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="多窗口模式" tabindex="-1">多窗口模式 <a class="header-anchor" href="#多窗口模式" aria-label="Permalink to &quot;多窗口模式&quot;">​</a></h1><p>多窗口模式可以把工具或局部面板从主窗口中分离出来，放到独立窗口里使用。它适合双屏工作、长时间监控、边聊边查资料，以及把输入框或监控面板固定在顺手的位置。</p><h2 id="适合什么场景" tabindex="-1">适合什么场景 <a class="header-anchor" href="#适合什么场景" aria-label="Permalink to &quot;适合什么场景&quot;">​</a></h2><ul><li>一边在 LLM 对话中写提示词，一边把参考工具放在另一个屏幕。</li><li>把 VCP 连接器的消息监控面板单独悬浮，避免频繁切换标签。</li><li>调试组件状态同步时，将测试面板分离成独立窗口观察。</li><li>在长对话中，把输入区域或辅助面板放到更靠近手边的位置。</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="分离整个工具" tabindex="-1">分离整个工具 <a class="header-anchor" href="#分离整个工具" aria-label="Permalink to &quot;分离整个工具&quot;">​</a></h3><ol><li>在主页打开一个工具。</li><li>在左侧已打开工具列表中找到该工具图标。</li><li>右键工具图标，选择分离相关操作；部分工具也支持拖拽触发分离。</li><li>分离窗口打开后，主窗口会保留原工具入口，方便你继续切换其他工具。</li></ol><p>如果窗口已经打开，再次触发分离通常会聚焦已有窗口，而不是重复创建。</p><h3 id="分离局部组件" tabindex="-1">分离局部组件 <a class="header-anchor" href="#分离局部组件" aria-label="Permalink to &quot;分离局部组件&quot;">​</a></h3><p>部分工具提供可分离的局部组件，例如组件测试器的同步测试面板、VCP 连接器的消息监控面板，以及 LLM Chat 中适配悬浮输入体验的区域。</p><p>常见入口包括：</p><ul><li>组件标题栏中的拖拽手柄。</li><li>面板工具栏中的分离按钮。</li><li>面板右键或更多菜单中的分离操作。</li></ul><p>分离后，主窗口一般会显示占位提示或收回按钮；点击收回后，对应窗口会关闭并恢复到主窗口。</p><h2 id="窗口控制" tabindex="-1">窗口控制 <a class="header-anchor" href="#窗口控制" aria-label="Permalink to &quot;窗口控制&quot;">​</a></h2><h3 id="返回主窗口" tabindex="-1">返回主窗口 <a class="header-anchor" href="#返回主窗口" aria-label="Permalink to &quot;返回主窗口&quot;">​</a></h3><p>分离窗口标题栏会提供返回主窗口的按钮。点击后，窗口关闭，主窗口中的工具或组件恢复内嵌显示。</p><h3 id="聚焦已有窗口" tabindex="-1">聚焦已有窗口 <a class="header-anchor" href="#聚焦已有窗口" aria-label="Permalink to &quot;聚焦已有窗口&quot;">​</a></h3><p>如果你忘记某个窗口已经打开，可以再次点击分离入口。系统会优先尝试聚焦已有窗口。主窗口的标题栏和工具侧边栏也会同步已分离状态。</p><h3 id="自动调整位置" tabindex="-1">自动调整位置 <a class="header-anchor" href="#自动调整位置" aria-label="Permalink to &quot;自动调整位置&quot;">​</a></h3><p>如果启用了窗口位置自动调整，AIO Hub 会定期检查分离窗口是否仍在可见屏幕范围内。外接显示器断开、分辨率变化后，这个功能能减少窗口跑到屏幕外的情况。</p><p>入口：设置 -&gt; 通用与启动项，查找窗口位置相关选项。</p><h2 id="状态同步" tabindex="-1">状态同步 <a class="header-anchor" href="#状态同步" aria-label="Permalink to &quot;状态同步&quot;">​</a></h2><p>多窗口不是简单复制界面。主窗口、分离工具窗口、分离组件窗口之间会通过同步总线交换状态：</p><ul><li>主窗口和分离工具窗口可以作为状态源。</li><li>分离组件窗口会向父窗口请求初始状态。</li><li>组件里的操作会通过远程 Action 回到父窗口执行。</li><li>设置、主题和窗口状态会尽量保持一致。</li></ul><p>因此，在分离输入框或监控面板中完成的操作，会同步影响原工具的实际状态。</p><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>把高频输入区域放在主屏，把监控或参考工具放在副屏。</li><li>长时间运行的监控窗口不要开太多，避免桌面杂乱。</li><li>如果发现窗口内容不同步，先收回再重新分离。</li><li>如果分离窗口无法找回，回到设置中开启窗口位置自动调整，或重启应用清理旧状态。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么有些工具不能分离局部面板" tabindex="-1">为什么有些工具不能分离局部面板？ <a class="header-anchor" href="#为什么有些工具不能分离局部面板" aria-label="Permalink to &quot;为什么有些工具不能分离局部面板？&quot;">​</a></h3><p>只有工具显式注册了可分离组件，局部面板才会出现分离入口。没有注册的工具仍可尝试分离整个工具窗口。</p><h3 id="关闭分离窗口会丢数据吗" tabindex="-1">关闭分离窗口会丢数据吗？ <a class="header-anchor" href="#关闭分离窗口会丢数据吗" aria-label="Permalink to &quot;关闭分离窗口会丢数据吗？&quot;">​</a></h3><p>正常关闭会触发重新附着流程，状态会回到主窗口。尚未保存的编辑内容仍建议先保存或发送后再关闭。</p><h3 id="分离窗口中的设置按钮会打开哪里" tabindex="-1">分离窗口中的设置按钮会打开哪里？ <a class="header-anchor" href="#分离窗口中的设置按钮会打开哪里" aria-label="Permalink to &quot;分离窗口中的设置按钮会打开哪里？&quot;">​</a></h3><p>在分离窗口中打开设置时，系统会尽量聚焦主窗口并跳转到对应设置页，避免在多个窗口里同时编辑全局设置。</p><h3 id="可以把同一个组件分离多次吗" tabindex="-1">可以把同一个组件分离多次吗？ <a class="header-anchor" href="#可以把同一个组件分离多次吗" aria-label="Permalink to &quot;可以把同一个组件分离多次吗？&quot;">​</a></h3><p>通常不建议也不会重复创建。系统会根据组件 ID 识别已有窗口，重复操作会优先聚焦现有窗口。</p>',36)])])}const b=e(t,[["render",o]]);export{p as __pageData,b as default};
